<?php
require_once __DIR__.'/../../config.php';redirect_if_not_logged_in();mb_require_any_permission($pdo,['view_proposals','manage_proposals']);require_once __DIR__.'/../_shared/workspace.php';ensure_maorin_workspace_tables($pdo);$can=current_user_can($pdo,'manage_proposals');$projects=mb_project_options($pdo);$estimates=$pdo->query("SELECT id,title,grand_total FROM mb_estimates ORDER BY id DESC")->fetchAll(PDO::FETCH_ASSOC);$edit=null;
if($_SERVER['REQUEST_METHOD']==='POST'&&$can){try{csrf_verify();$a=$_POST['action']??'';if($a==='save'){$id=(int)($_POST['id']??0);$data=[$_POST['project_id']?:null,$_POST['estimate_id']?:null,trim($_POST['proposal_no']??''),trim($_POST['title']??''),trim($_POST['client_name']??''),trim($_POST['status']??'draft'),(float)($_POST['amount']??0),$_POST['valid_until']?:null,trim($_POST['scope']??''),trim($_POST['terms']??'')];if($data[3]==='')throw new RuntimeException('Title required.');if($id){$pdo->prepare("UPDATE mb_proposals SET project_id=?,estimate_id=?,proposal_no=?,title=?,client_name=?,status=?,amount=?,valid_until=?,scope=?,terms=? WHERE id=?")->execute([...$data,$id]);mb_set_success('Proposal updated.');}else{$pdo->prepare("INSERT INTO mb_proposals (project_id,estimate_id,proposal_no,title,client_name,status,amount,valid_until,scope,terms,created_by) VALUES (?,?,?,?,?,?,?,?,?,?,?)")->execute([...$data,(int)$_SESSION['user_id']]);mb_set_success('Proposal created.');}}elseif($a==='delete'){$pdo->prepare("DELETE FROM mb_proposals WHERE id=?")->execute([(int)$_POST['id']]);mb_set_success('Proposal deleted.');}}catch(Throwable $e){mb_set_error($e->getMessage());}mb_redirect('index.php');}
if(isset($_GET['edit'])){$st=$pdo->prepare("SELECT * FROM mb_proposals WHERE id=?");$st->execute([(int)$_GET['edit']]);$edit=$st->fetch(PDO::FETCH_ASSOC);} $rows=$pdo->query("SELECT pr.*,p.name project_name,e.title estimate_title FROM mb_proposals pr LEFT JOIN mb_projects p ON p.id=pr.project_id LEFT JOIN mb_estimates e ON e.id=pr.estimate_id ORDER BY pr.updated_at DESC,pr.id DESC")->fetchAll(PDO::FETCH_ASSOC);[$ok,$err]=mb_flash();mb_workspace_header($pdo,'Proposals','Proposals'); ?>
<?php if($ok):?><div class="alert alert-success"><?=htmlspecialchars($ok)?></div><?php endif;?><?php if($err):?><div class="alert alert-danger"><?=htmlspecialchars($err)?></div><?php endif;?><div class="mb-card"><div class="mb-card-header"><div><strong>Client proposals</strong><div class="text-muted small">Create proposal records from estimates and projects.</div></div><?php if($can):?><button class="btn btn-primary" data-mb-open-modal="proposalModal">New Proposal</button><?php endif;?></div><div class="table-responsive"><table class="table mb-table"><thead><tr><th>No.</th><th>Title</th><th>Project</th><th>Estimate</th><th>Client</th><th>Status</th><th>Amount</th><th>Valid Until</th><th></th></tr></thead><tbody><?php foreach($rows as $r):?><tr><td><?=htmlspecialchars($r['proposal_no']?:$r['id'])?></td><td><strong><?=htmlspecialchars($r['title'])?></strong></td><td><?=htmlspecialchars($r['project_name']?:'-')?></td><td><?=htmlspecialchars($r['estimate_title']?:'-')?></td><td><?=htmlspecialchars($r['client_name'])?></td><td><span class="mb-badge <?= $r['status']==='approved'?'success':($r['status']==='rejected'?'danger':'') ?>"><?=htmlspecialchars($r['status'])?></span></td><td>₱<?=mb_money($r['amount'])?></td><td><?=htmlspecialchars($r['valid_until']?:'-')?></td><td class="mb-actions"><?php if($can):?><a class="btn btn-sm btn-outline-primary" href="?edit=<?=(int)$r['id']?>">Edit</a><form method="post"><input type="hidden" name="csrf_token" value="<?=htmlspecialchars(csrf_token())?>"><input type="hidden" name="action" value="delete"><input type="hidden" name="id" value="<?=(int)$r['id']?>"><button class="btn btn-sm btn-outline-danger" data-confirm="Delete proposal?">Delete</button></form><?php endif;?></td></tr><?php endforeach;if(!$rows):?><tr><td colspan="9" class="text-center text-muted py-4">No proposals yet.</td></tr><?php endif;?></tbody></table></div></div><div class="modal fade" id="proposalModal"><div class="modal-dialog modal-xl"><form method="post" class="modal-content mb-modal-panel"><input type="hidden" name="csrf_token" value="<?=htmlspecialchars(csrf_token())?>"><input type="hidden" name="action" value="save"><input type="hidden" name="id" value="<?=(int)($edit['id']??0)?>"><div class="modal-header"><h5 class="modal-title"><?=$edit?'Edit':'New'?> Proposal</h5><button class="btn-close" type="button" data-bs-dismiss="modal"></button></div><div class="modal-body"><div class="mb-form-grid"><label>Project<select class="form-select" name="project_id"><option value="">No project</option><?php foreach($projects as $p):?><option value="<?=(int)$p['id']?>" <?=((int)($edit['project_id']??0)===(int)$p['id']?'selected':'')?>><?=htmlspecialchars($p['name'])?></option><?php endforeach;?></select></label><label>Estimate<select class="form-select" name="estimate_id"><option value="">No estimate</option><?php foreach($estimates as $e):?><option value="<?=(int)$e['id']?>" <?=((int)($edit['estimate_id']??0)===(int)$e['id']?'selected':'')?>><?=htmlspecialchars($e['title'])?> - ₱<?=mb_money($e['grand_total'])?></option><?php endforeach;?></select></label><label>Proposal No.<input class="form-control" name="proposal_no" value="<?=htmlspecialchars($edit['proposal_no']??'')?>"></label><label>Title<input required class="form-control" name="title" value="<?=htmlspecialchars($edit['title']??'')?>"></label><label>Client<input class="form-control" name="client_name" value="<?=htmlspecialchars($edit['client_name']??'')?>"></label><label>Status<select class="form-select" name="status"><?php foreach(['draft','sent','approved','rejected','revised'] as $s):?><option <?=($edit['status']??'')===$s?'selected':''?>><?=$s?></option><?php endforeach;?></select></label><label>Amount<input class="form-control" type="number" step="0.01" name="amount" value="<?=htmlspecialchars($edit['amount']??'0')?>"></label><label>Valid Until<input class="form-control" type="date" name="valid_until" value="<?=htmlspecialchars($edit['valid_until']??'')?>"></label><label class="full">Scope<textarea class="form-control" rows="4" name="scope"><?=htmlspecialchars($edit['scope']??'')?></textarea></label><label class="full">Terms<textarea class="form-control" rows="4" name="terms"><?=htmlspecialchars($edit['terms']??'')?></textarea></label></div></div><div class="modal-footer"><button class="btn btn-primary">Save Proposal</button></div></form></div></div><script><?php if($edit):?>new bootstrap.Modal(document.getElementById('proposalModal')).show();<?php endif;?></script><?php mb_workspace_footer();?>